struct TriggerLocalScopes {
    scopes: Vec<Row>,
    types: Vec<HashMap<String, String>>,
    truncate_fractional: bool,
}

impl TriggerLocalScopes {
    fn new(truncate_fractional: bool) -> Self {
        Self {
            scopes: vec![Row::new()],
            types: vec![HashMap::new()],
            truncate_fractional,
        }
    }

    fn set_truncate_fractional(&mut self, truncate_fractional: bool) {
        self.truncate_fractional = truncate_fractional;
    }

    fn push_scope(&mut self) {
        self.scopes.push(Row::new());
        self.types.push(HashMap::new());
    }

    fn pop_scope(&mut self) {
        debug_assert!(self.scopes.len() > 1);
        self.scopes.pop();
        self.types.pop();
    }

    fn current_contains(&self, name: &str) -> bool {
        self.scopes.last().is_some_and(|scope| scope.contains(name))
    }

    fn contains(&self, name: &str) -> bool {
        self.scopes.iter().rev().any(|scope| scope.contains(name))
    }

    fn is_null(&self, name: &str) -> bool {
        self.scopes
            .iter()
            .rev()
            .find(|scope| scope.contains(name))
            .is_some_and(|scope| scope.is_null(name))
    }

    fn get(&self, name: &str) -> Option<&[u8]> {
        self.scopes
            .iter()
            .rev()
            .find(|scope| scope.contains(name))
            .and_then(|scope| scope.get(name))
    }

    fn declare(
        &mut self,
        name: &str,
        data_type: &str,
        value: Option<Vec<u8>>,
    ) -> anyhow::Result<()> {
        let value = coerce_trigger_local_value(data_type, value, self.truncate_fractional)?;
        let scope = self.scopes.last_mut().expect("root trigger scope");
        match value {
            Some(value) => scope.push(name, value),
            None => scope.push_null(name),
        }
        self.types
            .last_mut()
            .expect("root trigger type scope")
            .insert(name.to_ascii_lowercase(), data_type.to_string());
        Ok(())
    }

    fn set(&mut self, name: &str, value: Option<Vec<u8>>) -> anyhow::Result<bool> {
        let Some(index) = self
            .scopes
            .iter()
            .enumerate()
            .rev()
            .find(|(_, scope)| scope.contains(name))
            .map(|(index, _)| index)
        else {
            return Ok(false);
        };
        let data_type = self.types[index]
            .get(&name.to_ascii_lowercase())
            .expect("declared trigger variable type");
        let value = coerce_trigger_local_value(data_type, value, self.truncate_fractional)?;
        let scope = &mut self.scopes[index];
        match value {
            Some(value) => scope.set(name, value),
            None => scope.set_null(name),
        }
        Ok(true)
    }

    fn merged_row(&self) -> Row {
        let mut output = Row::new();
        for scope in &self.scopes {
            for (name, value) in &scope.values {
                if scope.is_null(name) {
                    output.set_null(name);
                } else {
                    output.set(name, value.clone());
                }
            }
        }
        output
    }
}

