    async fn transaction_backends() -> (
        tempfile::TempDir,
        Arc<StorageEngineManager>,
        Backend,
        Backend,
    ) {
        let temp = tempfile::tempdir().unwrap();
        let storage = Arc::new(StorageEngineManager::new(
            temp.path().to_path_buf(),
            16384,
            "4M",
        ));
        storage.init().await.unwrap();
        storage.create_database("mydb").await.unwrap();
        let stats = Arc::new(WireStats::default());
        let protocol = ProtocolConfig {
            lock_wait_timeout_ms: 100,
            ..ProtocolConfig::default()
        };
        let config = Arc::new(protocol);
        let mut first = Backend::new(storage.clone(), config.clone(), stats.clone(), 1);
        first
            .execute("CREATE TABLE actors (id BIGINT PRIMARY KEY, value BIGINT NOT NULL)")
            .await
            .unwrap();
        first
            .execute("INSERT INTO actors (id,value) VALUES (1,10)")
            .await
            .unwrap();
        let second = Backend::new(storage.clone(), config, stats, 2);
        (temp, storage, first, second)
    }

    fn single_value(outcome: QueryOutcome) -> Vec<u8> {
        match outcome {
            QueryOutcome::Rows { rows, .. } => rows[0][0].clone().unwrap(),
            QueryOutcome::Ok { .. } => panic!("expected row result"),
            QueryOutcome::Multiple { .. } => panic!("expected a single row result"),
        }
    }

    #[test]
    fn auth_catalog_persists_users_roles_and_database_grants() {
        let directory = tempfile::tempdir().unwrap();
        let catalog = AuthCatalog::open(directory.path(), "root", "root-password").unwrap();
        catalog
            .create_users(
                &[("game_writer".to_string(), "writer-password".to_string())],
                false,
            )
            .unwrap();
        catalog
            .create_roles(&["analyst".to_string()], false)
            .unwrap();
        catalog
            .grant_privileges(
                &["game_writer".to_string()],
                Some("game"),
                HashSet::from(["INSERT".to_string(), "UPDATE".to_string()]),
            )
            .unwrap();
        catalog
            .grant_roles(&["analyst".to_string()], &["game_writer".to_string()])
            .unwrap();
        drop(catalog);

        let restarted = AuthCatalog::open(directory.path(), "ignored", "ignored").unwrap();
        assert!(restarted.has_privilege("game_writer", "game", "INSERT"));
        assert!(restarted.has_privilege("game_writer", "game", "UPDATE"));
        assert!(!restarted.has_privilege("game_writer", "game", "DELETE"));
        assert!(restarted.data.read().users["game_writer"]
            .roles
            .contains("analyst"));
    }

    #[test]
    fn audit_log_rotates_and_limits_retention() {
        let directory = tempfile::tempdir().unwrap();
        let audit = AuditLog::open_with_rotation(directory.path(), "1", 2).unwrap();
        audit.record("statement", "root", "SELECT", "ok").unwrap();
        audit.record("statement", "root", "SELECT", "ok").unwrap();
        audit.record("statement", "root", "SELECT", "ok").unwrap();
        let snapshot = audit.snapshot();
        assert!(snapshot.healthy);
        assert_eq!(snapshot.accepted, 3);
        assert_eq!(snapshot.rejected, 0);
        audit.flush().unwrap();
        let audit_directory = directory.path().join("audit");
        assert!(audit_directory.join("events.ndjson").exists());
        assert!(audit_directory.join("events.ndjson.1").exists());
        assert!(audit_directory.join("events.ndjson.2").exists());
        assert!(!audit_directory.join("events.ndjson.3").exists());
    }

