    #[tokio::test]
    async fn mysql_temporal_format_roundtrip_supports_imports_and_transactions() {
        let (_temp, _storage, mut backend, _second) = transaction_backends().await;
        assert_eq!(
            query_rows(
                &mut backend,
                "SELECT GET_FORMAT(DATE,'USA'),GET_FORMAT(DATE,'EUR'),
                        GET_FORMAT(DATETIME,'INTERNAL'),
                        GET_FORMAT(TIME,'USA'),
                        DATE_FORMAT(
                            '2003-10-03',
                            GET_FORMAT(DATE,'EUR')
                        ),
                        STR_TO_DATE(
                            '10.31.2003',
                            GET_FORMAT(DATE,'USA')
                        ),
                        STR_TO_DATE('01,5,2013','%d,%m,%Y'),
                        STR_TO_DATE('May 1, 2013','%M %d, %Y'),
                        STR_TO_DATE(
                            '2026-07-17 23:45:06.123456',
                            '%Y-%m-%d %H:%i:%s.%f'
                        ),
                        STR_TO_DATE('11:45:06 PM','%h:%i:%s %p'),
                        TIME_FORMAT(
                            '100:00:00',
                            '%H %k %h %I %l'
                        ),
                        TIME_FORMAT(
                            '23:05:06.123456',
                            '%r %T %f'
                        ),
                        GET_FORMAT(DATE,'invalid'),
                        STR_TO_DATE(NULL,'%Y-%m-%d'),
                        TIME_FORMAT('invalid','%H:%i:%s')",
            )
            .await,
            vec![vec![
                Some(b"%m.%d.%Y".to_vec()),
                Some(b"%d.%m.%Y".to_vec()),
                Some(b"%Y%m%d%H%i%s".to_vec()),
                Some(b"%h:%i:%s %p".to_vec()),
                Some(b"03.10.2003".to_vec()),
                Some(b"2003-10-31".to_vec()),
                Some(b"2013-05-01".to_vec()),
                Some(b"2013-05-01".to_vec()),
                Some(b"2026-07-17 23:45:06.123456".to_vec()),
                Some(b"23:45:06".to_vec()),
                Some(b"100 100 04 04 4".to_vec()),
                Some(b"11:05:06 PM 23:05:06 123456".to_vec()),
                None,
                None,
                None,
            ]]
        );

        backend
            .execute(
                "CREATE TABLE imported_events (
                    id BIGINT PRIMARY KEY,
                    raw_date VARCHAR(32),
                    raw_time VARCHAR(32),
                    parsed_date DATE,
                    parsed_time TIME,
                    display_time VARCHAR(32)
                )",
            )
            .await
            .unwrap();
        backend
            .execute(
                "INSERT INTO imported_events
                 VALUES (
                    1,'07.17.2026','23:45:06',
                    '2000-01-01','00:00:00','old'
                 )",
            )
            .await
            .unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute(
                        "SELECT id FROM imported_events
                         WHERE STR_TO_DATE(
                                   raw_date,
                                   GET_FORMAT(DATE,'USA')
                               )='2026-07-17'",
                    )
                    .await
                    .unwrap()
            ),
            b"1"
        );
        backend.execute("BEGIN").await.unwrap();
        backend
            .execute(
                "UPDATE imported_events
                 SET parsed_date=STR_TO_DATE(
                         raw_date,
                         GET_FORMAT(DATE,'USA')
                     ),
                     parsed_time=STR_TO_DATE(raw_time,'%H:%i:%s'),
                     display_time=TIME_FORMAT(
                         STR_TO_DATE(raw_time,'%H:%i:%s'),
                         '%r'
                     )
                 WHERE id=1",
            )
            .await
            .unwrap();
        assert_eq!(
            query_rows(
                &mut backend,
                "SELECT parsed_date,parsed_time,display_time
                 FROM imported_events WHERE id=1",
            )
            .await,
            vec![vec![
                Some(b"2026-07-17".to_vec()),
                Some(b"23:45:06".to_vec()),
                Some(b"11:45:06 PM".to_vec()),
            ]]
        );
        backend.execute("ROLLBACK").await.unwrap();
        assert_eq!(
            query_rows(
                &mut backend,
                "SELECT parsed_date,parsed_time,display_time
                 FROM imported_events WHERE id=1",
            )
            .await,
            vec![vec![
                Some(b"2000-01-01".to_vec()),
                Some(b"00:00:00".to_vec()),
                Some(b"old".to_vec()),
            ]]
        );
    }

    #[tokio::test]
