    #[tokio::test]
    async fn numeric_update_expressions_are_atomic_mysql_compatible_and_transactional() {
        let (_temp, storage, mut backend, _second) = transaction_backends().await;
        backend
            .execute("ALTER TABLE actors ADD COLUMN nullable_value BIGINT NULL")
            .await
            .unwrap();

        backend
            .execute("UPDATE actors SET value=value+0.5, value=value*2 WHERE id=1")
            .await
            .unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"22"
        );
        backend
            .execute("UPDATE actors SET value=value/4 WHERE id=1")
            .await
            .unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"6"
        );
        let nullable = backend
            .execute("SELECT nullable_value FROM actors WHERE id=1")
            .await
            .unwrap();
        let QueryOutcome::Rows { rows, .. } = nullable else {
            panic!("expected row result")
        };
        assert_eq!(rows[0][0], None);
        backend
            .execute("UPDATE actors SET nullable_value=nullable_value+1 WHERE id=1")
            .await
            .unwrap();
        let database = storage.get_database("mydb").unwrap();
        assert!(database.scan_table("actors").unwrap()[0].is_null("nullable_value"));

        backend.execute("BEGIN").await.unwrap();
        backend
            .execute("UPDATE actors SET value=value+4 WHERE id=1")
            .await
            .unwrap();
        backend
            .execute("UPDATE actors SET value=value*2 WHERE id=1")
            .await
            .unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"20"
        );
        backend.execute("ROLLBACK").await.unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"6"
        );
    }

