    #[tokio::test]
    async fn ordered_limited_update_delete_follow_actor_and_transaction_order() {
        let (_temp, _storage, mut backend, _second) = transaction_backends().await;
        backend
            .execute("INSERT INTO actors VALUES (2,20),(3,30),(4,40)")
            .await
            .unwrap();
        backend
            .execute("UPDATE actors SET value=value+1 ORDER BY id DESC LIMIT 2")
            .await
            .unwrap();
        backend
            .execute("UPDATE actors SET value=99 ORDER BY id ASC LIMIT 1")
            .await
            .unwrap();
        let outcome = backend
            .execute("SELECT id,value FROM actors ORDER BY id")
            .await
            .unwrap();
        let QueryOutcome::Rows { rows, .. } = outcome else {
            panic!("expected rows")
        };
        assert_eq!(
            rows,
            vec![
                vec![Some(b"1".to_vec()), Some(b"99".to_vec())],
                vec![Some(b"2".to_vec()), Some(b"20".to_vec())],
                vec![Some(b"3".to_vec()), Some(b"31".to_vec())],
                vec![Some(b"4".to_vec()), Some(b"41".to_vec())],
            ]
        );

        backend.execute("BEGIN").await.unwrap();
        backend
            .execute("DELETE FROM actors ORDER BY value DESC LIMIT 1")
            .await
            .unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute("SELECT COUNT(*) FROM actors")
                    .await
                    .unwrap()
            ),
            b"3"
        );
        backend.execute("ROLLBACK").await.unwrap();
        assert_eq!(
            single_value(
                backend
                    .execute("SELECT COUNT(*) FROM actors")
                    .await
                    .unwrap()
            ),
            b"4"
        );

        backend
            .execute("DELETE FROM actors ORDER BY id ASC LIMIT 2")
            .await
            .unwrap();
        backend
            .execute("UPDATE actors SET id=id+1 ORDER BY id DESC")
            .await
            .unwrap();
        let outcome = backend
            .execute("SELECT id,value FROM actors ORDER BY id")
            .await
            .unwrap();
        let QueryOutcome::Rows { rows, .. } = outcome else {
            panic!("expected rows")
        };
        assert_eq!(
            rows,
            vec![
                vec![Some(b"4".to_vec()), Some(b"31".to_vec())],
                vec![Some(b"5".to_vec()), Some(b"41".to_vec())],
            ]
        );
    }

