    #[tokio::test]
    async fn read_uncommitted_sees_dirty_writes_until_rollback_or_disconnect() {
        let (_temp, _storage, mut writer, mut reader) = transaction_backends().await;
        reader
            .execute("SET SESSION TRANSACTION ISOLATION LEVEL READ UNCOMMITTED")
            .await
            .unwrap();
        reader.execute("BEGIN").await.unwrap();

        writer.execute("BEGIN").await.unwrap();
        writer
            .execute("UPDATE actors SET value=99 WHERE id=1")
            .await
            .unwrap();
        writer
            .execute("INSERT INTO actors (id,value) VALUES (2,22)")
            .await
            .unwrap();
        assert_eq!(
            single_value(
                reader
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"99"
        );
        assert_eq!(
            single_value(reader.execute("SELECT COUNT(*) FROM actors").await.unwrap()),
            b"2"
        );

        writer.execute("ROLLBACK").await.unwrap();
        assert_eq!(
            single_value(
                reader
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"10"
        );
        assert_eq!(
            single_value(reader.execute("SELECT COUNT(*) FROM actors").await.unwrap()),
            b"1"
        );

        writer.execute("BEGIN").await.unwrap();
        writer
            .execute("UPDATE actors SET value=77 WHERE id=1")
            .await
            .unwrap();
        assert_eq!(
            single_value(
                reader
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"77"
        );
        drop(writer);
        assert_eq!(
            single_value(
                reader
                    .execute("SELECT value FROM actors WHERE id=1")
                    .await
                    .unwrap()
            ),
            b"10"
        );
    }

