    #[tokio::test]
    async fn same_primary_key_waits_and_reports_timeout_metrics() {
        let (_temp, _storage, mut first, mut second) = transaction_backends().await;
        let stats = second.stats.clone();
        first.execute("BEGIN").await.unwrap();
        first
            .execute("UPDATE actors SET value=11 WHERE id=1")
            .await
            .unwrap();

        let error = second
            .execute("UPDATE actors SET value=12 WHERE id=1")
            .await
            .unwrap_err();
        assert!(error.to_string().contains("Lock wait timeout exceeded"));
        let snapshot = stats.snapshot();
        assert_eq!(snapshot.lock_waits, 1);
        assert_eq!(snapshot.lock_timeouts, 1);
        assert!(snapshot.active_locks >= 3);

        first.execute("ROLLBACK").await.unwrap();
        second
            .execute("UPDATE actors SET value=12 WHERE id=1")
            .await
            .unwrap();
        assert_eq!(stats.snapshot().active_locks, 0);
    }

