    #[tokio::test]
    async fn for_share_and_nowait_match_mysql_lock_compatibility() {
        let (_temp, _storage, mut first, mut second) = transaction_backends().await;
        second
            .execute("INSERT INTO actors (id,value) VALUES (2,20)")
            .await
            .unwrap();
        let stats = first.stats.clone();

        first.execute("BEGIN").await.unwrap();
        assert_eq!(
            single_value(
                first
                    .execute("SELECT value FROM actors WHERE id=1 FOR SHARE")
                    .await
                    .unwrap()
            ),
            b"10"
        );
        second.execute("BEGIN").await.unwrap();
        assert_eq!(
            single_value(
                second
                    .execute("SELECT value FROM actors WHERE id=1 FOR SHARE NOWAIT")
                    .await
                    .unwrap()
            ),
            b"10"
        );

        let error = second
            .execute("SELECT value FROM actors WHERE id=1 FOR UPDATE NOWAIT")
            .await
            .unwrap_err()
            .to_string();
        assert_eq!(
            error,
            "Statement aborted because lock(s) could not be acquired immediately and NOWAIT is set."
        );
        assert_eq!(mysql_error_kind(&error), ErrorKind::ER_LOCK_NOWAIT);
        assert_eq!(stats.snapshot().lock_waits, 1);
        assert_eq!(stats.snapshot().lock_timeouts, 0);

        second
            .execute("UPDATE actors SET value=21 WHERE id=2")
            .await
            .unwrap();
        second.execute("ROLLBACK").await.unwrap();
        let error = second
            .execute("UPDATE actors SET value=11 WHERE id=1")
            .await
            .unwrap_err()
            .to_string();
        assert!(error.contains("Lock wait timeout exceeded"));

        first.execute("COMMIT").await.unwrap();
        second
            .execute("UPDATE actors SET value=11 WHERE id=1")
            .await
            .unwrap();
    }

